Get-Process -Name msedge, Cortana -ErrorAction SilentlyContinue | Stop-Process -Force; $null = Set-ItemProperty -Path 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Search' -Name 'SearchboxTaskbarMode' -Value 0 -ErrorAction SilentlyContinue; $null = Set-ItemProperty -Path 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\Windows Search' -Name 'AllowCortana' -Value 0 -ErrorAction SilentlyContinue; $null = Set-ItemProperty -Path 'HKLM:\SOFTWARE\Policies\Microsoft\MicrosoftEdge\Main' -Name 'AllowPrelaunch' -Value 0 -ErrorAction SilentlyContinue; $null = Set-ItemProperty -Path 'HKLM:\SOFTWARE\Policies\Microsoft\EdgeUpdate' -Name 'Allowsxs' -Value 0 -ErrorAction SilentlyContinue; Get-Service -Name edgeupdate, edgeupdatem -ErrorAction SilentlyContinue | Set-Service -StartupType Disabled; Get-ScheduledTask -TaskName *EdgeUpdate* -ErrorAction SilentlyContinue | Disable-ScheduledTask; Write-Host 'Servisai, Taskai ir Registras užrakinti.' -ForegroundColor Green
